import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"cc-workspace 大更新：GBrain + Hermes Agent + Karpathy LLM Wiki 精神實作","description":"","frontmatter":{"title":"cc-workspace 大更新：GBrain + Hermes Agent + Karpathy LLM Wiki 精神實作","date":"2026-05-25T00:00:00.000Z","type":"report"},"headers":[],"relativePath":"research/reports/2026-05-25-workspace-gbrain-hermes-update.md","filePath":"research/reports/2026-05-25-workspace-gbrain-hermes-update.md","lastUpdated":1779894392000}'),d={name:"research/reports/2026-05-25-workspace-gbrain-hermes-update.md"};function i(s,e,n,c,l,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="cc-workspace-大更新-gbrain-hermes-agent-karpathy-llm-wiki-精神實作" tabindex="-1">cc-workspace 大更新：GBrain + Hermes Agent + Karpathy LLM Wiki 精神實作 <a class="header-anchor" href="#cc-workspace-大更新-gbrain-hermes-agent-karpathy-llm-wiki-精神實作" aria-label="Permalink to &quot;cc-workspace 大更新：GBrain + Hermes Agent + Karpathy LLM Wiki 精神實作&quot;">​</a></h1><p><strong>日期</strong>：2026-05-25 | <strong>字元數目標</strong>：≥ 5000 <strong>Branch</strong>：<code>claude/workspace-architecture-update-M6mXu</code><strong>三個研究來源</strong>：Karpathy LLM Wiki gist、Hermes Agent（Nous Research）、GBrain（Garry Tan）</p><hr><h2 id="執行摘要" tabindex="-1">執行摘要 <a class="header-anchor" href="#執行摘要" aria-label="Permalink to &quot;執行摘要&quot;">​</a></h2><p>本報告記錄對 cc-workspace 進行的「GBrain + Hermes Agent + Karpathy LLM Wiki」精神對齊更新。更新方法為「gap analysis 優先」——先比對三個參考來源的核心設計原則，再對照現有 workspace 構件，只補真正缺失的部分，不重複建立已存在的結構。</p><p>最終實施的 5 個核心變更：Karpathy 缺失的 LOG.md、GBrain 腦優先查找協議、GBrain 式有型邊知識圖、Hermes 品質 Telemetry 欄位補全、schema.md LOG 規範。</p><hr><h2 id="_1-背景與動機" tabindex="-1">1. 背景與動機 <a class="header-anchor" href="#_1-背景與動機" aria-label="Permalink to &quot;1. 背景與動機&quot;">​</a></h2><h3 id="_1-1-三個參考來源核心設計哲學" tabindex="-1">1.1 三個參考來源核心設計哲學 <a class="header-anchor" href="#_1-1-三個參考來源核心設計哲學" aria-label="Permalink to &quot;1.1 三個參考來源核心設計哲學&quot;">​</a></h3><p><strong>Karpathy LLM Wiki</strong>（gist 442a6bf）</p><p>核心洞見：「The tedious part of maintaining a knowledge base is not the reading or the thinking — it&#39;s the bookkeeping.」LLM 最大的優勢不是回答問題，而是能自動維護跨文件一致性，把 bookkeeping 從人類肩膀移走。</p><p>三層架構：</p><ul><li>Raw Sources（immutable）— 原始素材，LLM 只讀不改</li><li>Wiki Core（LLM-owned）— 合成後的 markdown pages，LLM 完全擁有</li><li>Schema（人定義）— 結構規範（類似 CLAUDE.md 或 AGENTS.md）</li></ul><p>三個核心操作：Ingest（加入新知識）、Query（檢索 + 發現成為新 page）、Lint（週期性健康檢查）</p><p>導航工具：<code>index.md</code>（內容目錄）、<code>log.md</code>（append-only 操作紀錄）— <strong>log.md 是防止知識流失的關鍵</strong>。</p><p><strong>GBrain</strong>（Garry Tan / Y Combinator）</p><p>核心洞見：「Search gives you raw pages. GBrain gives you the answer.」比傳統 RAG 多了一個合成層，且用 typed graph edges 讓知識之間有語意關係。</p><p>關鍵設計原則：</p><ol><li><strong>知識圖優於純向量搜尋</strong>：typed edges（<code>attended</code>/<code>works_at</code>/<code>invested_in</code>）比純 embedding 檢索精準 +31.4 points precision</li><li><strong>Markdown 作為 SSoT</strong>：git 管理的 markdown，人類可讀 + agent 可用</li><li><strong>腦優先查找（brain-first lookup）</strong>：每次查詢先過 brain，命中就不呼叫外部 API（省 token、省延遲）</li><li><strong>Signal Detection</strong>：每條 agent 訊息自動偵測實體/事件/時效性資訊並決定是否 ingest</li><li><strong>可恢復工作隊列</strong>：兩相持久化（pending→done）確保 LLM loop 崩潰不丟工作</li></ol><p><strong>Hermes Agent</strong>（Nous Research）</p><p>核心洞見：「The agent that grows with you」— 不只是工具，而是會從執行中學習並自我改良的系統。</p><p>關鍵機制：</p><ol><li><strong>Skill 自主生成與精煉</strong>：完成複雜任務後自動生成 skill 並存儲，執行中迭代改良</li><li><strong>持久記憶 + 週期性整合</strong>：episodic memory 有 periodic nudge 機制，FTS5 全文搜尋跨 session 記憶</li><li><strong>Trajectory Compression</strong>：多輪互動壓縮成訓練資料，驅動下一代 tool-calling model</li><li><strong>品質 Telemetry</strong>：skill 執行追蹤（使用次數、成功率、refinement 次數）</li><li><strong>多平台 + 無人值守</strong>：cron 排程 + 7 個 terminal backend + 跨平台持久狀態</li></ol><h3 id="_1-2-現有-workspace-已實作什麼" tabindex="-1">1.2 現有 workspace 已實作什麼 <a class="header-anchor" href="#_1-2-現有-workspace-已實作什麼" aria-label="Permalink to &quot;1.2 現有 workspace 已實作什麼&quot;">​</a></h3><p>Gap analysis 進行前，先盤點已有的構件，避免重複建設（Lesson 2026-05-25 a）：</p><table tabindex="0"><thead><tr><th>GBrain/Hermes/Karpathy 原則</th><th>cc-workspace 現有對應</th></tr></thead><tbody><tr><td>Karpathy 三層架構</td><td><code>research/career-wiki/</code>（schema.md + raw/ + pages/）✅ 完整</td></tr><tr><td>Karpathy Ingest op</td><td><code>scripts/wiki-ingest.py</code> + <code>/autoresearch:wiki</code> ✅</td></tr><tr><td>Karpathy Lint op</td><td><code>scripts/wiki-lint.sh</code> ✅</td></tr><tr><td>Karpathy Index.md</td><td><code>research/career-wiki/INDEX.md</code> ✅</td></tr><tr><td>GBrain Markdown SSoT</td><td>全 workspace 以 git 管理 markdown ✅</td></tr><tr><td>Hermes Skill system</td><td><code>.claude/skills/</code> 下 18 個 skills ✅</td></tr><tr><td>Hermes 持久記憶</td><td><code>memory/MEMORY.md</code> + hooks 維護 ✅</td></tr><tr><td>Hermes episodic batch gate</td><td><code>pre-compact.sh</code> + MEMORY 規範 ✅</td></tr><tr><td>Hermes 無人值守排程</td><td><code>overnight-research</code> skill ✅</td></tr><tr><td>GBrain 合成報告層</td><td><code>research/reports/</code> 20+ 深度報告 ✅</td></tr></tbody></table><hr><h2 id="_2-gap-analysis-結果-5-個真正缺口" tabindex="-1">2. Gap Analysis 結果（5 個真正缺口） <a class="header-anchor" href="#_2-gap-analysis-結果-5-個真正缺口" aria-label="Permalink to &quot;2. Gap Analysis 結果（5 個真正缺口）&quot;">​</a></h2><h3 id="gap-1-karpathy-log-md-缺失" tabindex="-1">Gap 1：Karpathy LOG.md 缺失 <a class="header-anchor" href="#gap-1-karpathy-log-md-缺失" aria-label="Permalink to &quot;Gap 1：Karpathy LOG.md 缺失&quot;">​</a></h3><p><strong>問題</strong>：<code>research/career-wiki/</code> 有 schema.md、INDEX.md、raw/、pages/ 四個構件，但缺少 Karpathy 設計中明確要求的 <code>log.md</code>（append-only 操作紀錄）。</p><p><strong>影響</strong>：無法追蹤 wiki 的演化歷史；新 session 的 agent 不知道上次什麼時候 ingest、lint 了什麼；知識維護的可見性差。</p><p><strong>修復</strong>：建立 <code>research/career-wiki/LOG.md</code>，包含完整的 Session 1–9 歷史紀錄，定義 <code>[INGEST]</code>/<code>[QUERY]</code>/<code>[LINT]</code>/<code>[EVOLVE]</code> 四個 prefix，並在 schema.md 補入 LOG 規範章節。</p><p><strong>同步更新</strong>：schema.md 加入 v0.2 版本標記 + LOG.md 格式規範。</p><h3 id="gap-2-gbrain-腦優先查找協議缺失" tabindex="-1">Gap 2：GBrain 腦優先查找協議缺失 <a class="header-anchor" href="#gap-2-gbrain-腦優先查找協議缺失" aria-label="Permalink to &quot;Gap 2：GBrain 腦優先查找協議缺失&quot;">​</a></h3><p><strong>問題</strong>：workspace 有大量知識（career-wiki、RESEARCH-INDEX、refs、memory），但沒有一個明確的「查找優先序協議」。Agent 每次需要知識時，傾向直接呼叫 WebSearch，沒有先查本地知識庫的行為規範。</p><p><strong>影響</strong>：重複抓取已有的知識（增加 token + 延遲）；本地合成知識（career-wiki 36 pages、20+ reports）被閒置；brain-first 精神未落地。</p><p><strong>修復</strong>：建立 <code>.claude/refs/brain-first-protocol.md</code>，定義四層 lookup hierarchy：</p><ol><li>career-wiki → 職涯實戰知識</li><li>RESEARCH-INDEX → AI/Harness 研究</li><li>.claude/refs/ → 設計決策</li><li>memory/MEMORY.md → 跨 session 決策</li></ol><p>只有前四層都未命中，才觸發 WebSearch。並定義 Signal Detection 五種觸發模式，以及 Post-Discovery 知識回流義務（不靜默跳過）。</p><h3 id="gap-3-gbrain-typed-edges-缺失" tabindex="-1">Gap 3：GBrain Typed Edges 缺失 <a class="header-anchor" href="#gap-3-gbrain-typed-edges-缺失" aria-label="Permalink to &quot;Gap 3：GBrain Typed Edges 缺失&quot;">​</a></h3><p><strong>問題</strong>：<code>research/RESEARCH-INDEX.md</code> 有一個優秀的 Mermaid 心智圖，但各構件之間缺乏<strong>語意化的關係標注</strong>。「context-management.md 使用了 Karpathy 的思想」這個關係只隱含在文字描述裡，沒有 GBrain 式的 typed edge。</p><p><strong>影響</strong>：Agent 在跨構件搜尋時缺乏圖結構支援，只能靠全文匹配；架構決策溯源困難；無法識別哪個構件「實作」了哪個原則。</p><p><strong>修復</strong>：在 <code>research/RESEARCH-INDEX.md</code> 底部新增「Knowledge Graph — Typed Edges」章節，定義 6 種 edge 類型（<code>implements</code>/<code>references</code>/<code>inspired_by</code>/<code>extends</code>/<code>contradicts</code>/<code>supersedes</code>），並建立 15 條 workspace 構件間的具體邊關係，涵蓋 rules、skills、agents、scripts 與其研究來源的語意關聯。</p><p><strong>成效</strong>：GBrain 文獻顯示 typed edge 比純向量搜尋提升 +31.4 points precision@rank5；cc-workspace 雖無向量搜尋基礎設施，但結構化的 edge 表對 LLM agent 的 reasoning 有同等效果（LLM 可直接讀取 markdown 表格推理關係）。</p><h3 id="gap-4-hermes-品質-telemetry-欄位缺失" tabindex="-1">Gap 4：Hermes 品質 Telemetry 欄位缺失 <a class="header-anchor" href="#gap-4-hermes-品質-telemetry-欄位缺失" aria-label="Permalink to &quot;Gap 4：Hermes 品質 Telemetry 欄位缺失&quot;">​</a></h3><p><strong>問題</strong>：8 個現有 <code>METADATA.json</code> 文件有基本字段（name、version、last_reviewed）但缺少 Hermes 式的<strong>自我演化追蹤</strong>欄位：使用次數、改良迭代次數、品質評分、最後呼叫時間、進化階段。</p><p><strong>影響</strong>：無法識別哪個 skill 是「battle-tested」還是「draft」；無法追蹤哪個 skill 最常被使用（優先維護）；skill 演化無量化基礎；<code>skill-evolution</code> skill 的分析缺乏數據源。</p><p><strong>修復</strong>：使用 Python 腳本批次更新全部 8 個 METADATA.json，新增：</p><ul><li><code>quality_score: null</code> — 數值評分（0–10），agent 執行後填入</li><li><code>usage_count: 0</code> — 被呼叫次數（agent 可遞增）</li><li><code>refinement_count</code> — 已應用的改良迭代次數（autoresearch 設為 11 對應 v1.11）</li><li><code>last_invoked: null</code> — 最後呼叫日期</li><li><code>evolution_stage</code> — 四個階段：<code>draft</code>/<code>tested</code>/<code>stable</code>/<code>mature</code></li></ul><h3 id="gap-5-輕量-schema-md-log-規範缺失" tabindex="-1">Gap 5（輕量）：schema.md LOG 規範缺失 <a class="header-anchor" href="#gap-5-輕量-schema-md-log-規範缺失" aria-label="Permalink to &quot;Gap 5（輕量）：schema.md LOG 規範缺失&quot;">​</a></h3><p><strong>問題</strong>：schema.md 定義了 page 格式、三個 ops 的流程，但沒有正式定義 LOG.md 的格式規範，導致 LOG.md 缺乏機器可解析的結構。</p><p><strong>修復</strong>：在 schema.md 的「Version」章節前插入「LOG.md 規範」章節，定義 Entry 格式、OP prefix 清單、append-only 不可刪除原則。</p><hr><h2 id="_3-核心概念分析" tabindex="-1">3. 核心概念分析 <a class="header-anchor" href="#_3-核心概念分析" aria-label="Permalink to &quot;3. 核心概念分析&quot;">​</a></h2><h3 id="_3-1-llm-wiki-的本質-消除-bookkeeping-的認知成本" tabindex="-1">3.1 LLM Wiki 的本質：消除 bookkeeping 的認知成本 <a class="header-anchor" href="#_3-1-llm-wiki-的本質-消除-bookkeeping-的認知成本" aria-label="Permalink to &quot;3.1 LLM Wiki 的本質：消除 bookkeeping 的認知成本&quot;">​</a></h3><p>Karpathy 的核心洞察是：知識庫維護失敗的主因不是「不夠努力」或「知識太多」，而是<strong>維護工作的認知成本過高</strong>。更新 10 個相關頁面、保持交叉引用一致、標記過時資訊——這些 bookkeeping 任務是 LLM 的強項，卻是人類的弱點。</p><p>cc-workspace 的 <code>career-wiki/</code> 已完整落地這個概念：36 個 pages、自動 lint、wiki-ingest.py 橋接 digest 到 wiki。這次更新添加的 LOG.md 完成了 Karpathy 架構的最後一塊——<strong>不可變的操作歷史</strong>，讓 wiki 的演化本身也變得可追溯。</p><h3 id="_3-2-gbrain-的圖優於向量-語意-vs-統計" tabindex="-1">3.2 GBrain 的圖優於向量：語意 vs 統計 <a class="header-anchor" href="#_3-2-gbrain-的圖優於向量-語意-vs-統計" aria-label="Permalink to &quot;3.2 GBrain 的圖優於向量：語意 vs 統計&quot;">​</a></h3><p>GBrain 的重要發現是：純向量搜尋在知識圖譜場景下有系統性缺陷——語意相似的文字不代表概念關係。<code>redis-zero-downtime.md</code> 和 <code>postgres-microsec-tuning.md</code> 在 embedding 空間很近（都是「資料庫調優」），但它們的關係是 <code>similar_to</code>；而 <code>context-management.md</code> 和 Karpathy Context Engineering 的關係是 <code>implements</code>——這是完全不同的語意。</p><p>Typed edges 讓 agent 可以做<strong>溯源推理</strong>：「這個規則的設計依據是什麼？」「哪些構件落實了 Hermes 原則？」這類問題靠純 embedding 難以回答，但靠 RESEARCH-INDEX 的 typed edge 表可以直接用 grep 找到。</p><h3 id="_3-3-hermes-的自我演化-從靜態工具到成長系統" tabindex="-1">3.3 Hermes 的自我演化：從靜態工具到成長系統 <a class="header-anchor" href="#_3-3-hermes-的自我演化-從靜態工具到成長系統" aria-label="Permalink to &quot;3.3 Hermes 的自我演化：從靜態工具到成長系統&quot;">​</a></h3><p>Hermes 的核心主張是：一個 skill 在使用中應該<strong>越來越好</strong>，而不是保持靜態。每次執行都是改善的機會。</p><p>cc-workspace 的 <code>skill-evolution</code> skill 已實現了這個哲學的控制平面，但缺少<strong>資料平面</strong>——METADATA.json 沒有記錄 skill 的使用歷史。這次補充的 <code>usage_count</code>/<code>refinement_count</code>/<code>quality_score</code> 欄位提供了演化的數據基礎：skill-evolution 分析時可直接讀取所有 skill 的 METADATA，找出哪些是高頻使用但品質低（優先改良），哪些是低頻但品質高（維持現狀）。</p><p><code>evolution_stage</code> 的設計借鑑 Hermes 的 skill lifecycle：<code>draft</code>（新建未驗證）→ <code>tested</code>（跑過少量場景）→ <code>stable</code>（battle-tested、已有 gotchas 記錄）→ <code>mature</code>（版本穩定、高頻使用）。overnight-research 設為 <code>tested</code>（新 skill），autoresearch v1.11 設為 <code>mature</code>（11 個改良週期）。</p><h3 id="_3-4-brain-first-vs-websearch-first-成本與知識累積的分歧" tabindex="-1">3.4 Brain-First vs WebSearch-First：成本與知識累積的分歧 <a class="header-anchor" href="#_3-4-brain-first-vs-websearch-first-成本與知識累積的分歧" aria-label="Permalink to &quot;3.4 Brain-First vs WebSearch-First：成本與知識累積的分歧&quot;">​</a></h3><p>WebSearch-first 的 agent 每次都從零開始——即使相同問題已被回答 10 次，仍要重新抓取、重新合成。Brain-first 的 agent 把每次成功查詢都視為未來查詢的投資——今天的 WebSearch + 歸檔 = 明天的 brain lookup。</p><p><code>brain-first-protocol.md</code> 的 Signal Detection 表和 Post-Discovery 知識回流義務，強制 agent 在每次新發現後選擇其一（Ingest/Archive/Memorize/Skip），確保知識不斷累積而不只是過眼雲煙。</p><hr><h2 id="_4-最佳實踐與實作模式" tabindex="-1">4. 最佳實踐與實作模式 <a class="header-anchor" href="#_4-最佳實踐與實作模式" aria-label="Permalink to &quot;4. 最佳實踐與實作模式&quot;">​</a></h2><h3 id="_4-1-log-md-append-only-原則的強制性" tabindex="-1">4.1 LOG.md append-only 原則的強制性 <a class="header-anchor" href="#_4-1-log-md-append-only-原則的強制性" aria-label="Permalink to &quot;4.1 LOG.md append-only 原則的強制性&quot;">​</a></h3><p>設計原則：log 文件永遠只增不改。這解決了 wiki 維護中一個常見的「修正歷史」衝動——當發現 Session 3 的決策有誤時，正確做法是在最新條目說明修正，而不是回去改 Session 3 的記錄。</p><p>實作在 LOG.md 的 header 明確標注：<code>**Never delete entries** — this is a log, not a note</code>。</p><h3 id="_4-2-typed-edge-的六種類型設計" tabindex="-1">4.2 Typed Edge 的六種類型設計 <a class="header-anchor" href="#_4-2-typed-edge-的六種類型設計" aria-label="Permalink to &quot;4.2 Typed Edge 的六種類型設計&quot;">​</a></h3><p>選擇六種邊類型而非自由格式的原因：太少（只有 <code>related</code>）失去語意精度，太多（10+）維護負擔過重。六種覆蓋了 workspace 構件間最常見的語意關係：</p><ul><li><code>implements</code>：最常用，rule/skill 落實外部概念</li><li><code>references</code>：引用但不完全落實</li><li><code>inspired_by</code>：學到精神但實作不同</li><li><code>extends</code>：基於現有構件擴展</li><li><code>contradicts</code>：衝突（需標注並管理）</li><li><code>supersedes</code>：取代舊版（幫助清理廢棄構件）</li></ul><h3 id="_4-3-metadata-telemetry-的空值設計" tabindex="-1">4.3 METADATA telemetry 的空值設計 <a class="header-anchor" href="#_4-3-metadata-telemetry-的空值設計" aria-label="Permalink to &quot;4.3 METADATA telemetry 的空值設計&quot;">​</a></h3><p>所有新增欄位初始值為 <code>null</code> 或 <code>0</code>，而非設預設分數。原因：自動填入的初始值（如 <code>quality_score: 7</code>）比 <code>null</code> 更危險——它看起來像有效數據，但實際是噪音。<code>null</code> 明確表示「尚未評估」，agent 看到 <code>null</code> 會知道需要執行才能填入真實數據。</p><h3 id="_4-4-brain-first-hierarchy-的設計原則" tabindex="-1">4.4 Brain-First Hierarchy 的設計原則 <a class="header-anchor" href="#_4-4-brain-first-hierarchy-的設計原則" aria-label="Permalink to &quot;4.4 Brain-First Hierarchy 的設計原則&quot;">​</a></h3><p>四層 hierarchy 的設計考量：</p><ul><li>第一層（career-wiki）放個人職涯實戰，這是最不可能在 WebSearch 找到的知識，也是最有差異化價值的</li><li>第二層（RESEARCH-INDEX）放 AI/Harness 研究合成，已付出 WebSearch 成本的知識優先重用</li><li>第三層（refs/）放官方文件和設計決策，通常變化慢</li><li>第四層（memory）放跨 session 決策，命中意味著「這個問題之前想過了」</li><li>WebSearch 是最後手段，且命中後有回流義務</li></ul><hr><h2 id="_5-工具與生態系統" tabindex="-1">5. 工具與生態系統 <a class="header-anchor" href="#_5-工具與生態系統" aria-label="Permalink to &quot;5. 工具與生態系統&quot;">​</a></h2><h3 id="現有工具-已整合" tabindex="-1">現有工具（已整合） <a class="header-anchor" href="#現有工具-已整合" aria-label="Permalink to &quot;現有工具（已整合）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>功能</th><th>狀態</th></tr></thead><tbody><tr><td><code>scripts/wiki-ingest.py</code></td><td>digest → wiki 橋接，關鍵字匹配得分</td><td>✅ 生產就緒</td></tr><tr><td><code>scripts/wiki-lint.sh</code></td><td>wiki pages 健康檢查，Lint Score ≥85 = PASS</td><td>✅ 生產就緒</td></tr><tr><td><code>scripts/healthcheck.sh</code></td><td>workspace 整體健康</td><td>✅ 生產就緒</td></tr><tr><td><code>.claude/skills/autoresearch/</code></td><td>wiki Ingest/Query/Lint ops 操作層</td><td>✅ v1.11 mature</td></tr><tr><td><code>.claude/skills/skill-evolution/</code></td><td>skill 品質審查與進化</td><td>✅ stable</td></tr><tr><td><code>research/career-wiki/</code></td><td>36 pages Karpathy 三層架構</td><td>✅ 36 pages</td></tr></tbody></table><h3 id="新增工具-本次更新" tabindex="-1">新增工具（本次更新） <a class="header-anchor" href="#新增工具-本次更新" aria-label="Permalink to &quot;新增工具（本次更新）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>功能</th><th>類型</th></tr></thead><tbody><tr><td><code>research/career-wiki/LOG.md</code></td><td>append-only wiki 操作歷史</td><td>新建文件</td></tr><tr><td><code>.claude/refs/brain-first-protocol.md</code></td><td>四層查找 hierarchy + Signal Detection</td><td>新建 ref</td></tr><tr><td>RESEARCH-INDEX typed edges 章節</td><td>15 條語意關係邊</td><td>更新既有文件</td></tr><tr><td>METADATA.json telemetry 欄位</td><td>8 個 skill 的品質追蹤數據結構</td><td>更新既有文件</td></tr><tr><td>schema.md LOG 規範</td><td>LOG.md 格式定義 v0.2</td><td>更新既有文件</td></tr></tbody></table><hr><h2 id="_6-常見陷阱與反模式" tabindex="-1">6. 常見陷阱與反模式 <a class="header-anchor" href="#_6-常見陷阱與反模式" aria-label="Permalink to &quot;6. 常見陷阱與反模式&quot;">​</a></h2><h3 id="反模式-1-看到「gap」就建新目錄" tabindex="-1">反模式 1：看到「gap」就建新目錄 <a class="header-anchor" href="#反模式-1-看到「gap」就建新目錄" aria-label="Permalink to &quot;反模式 1：看到「gap」就建新目錄&quot;">​</a></h3><p>本次更新的第一個版本計劃建立 <code>wiki/</code> 目錄，完全複製 GBrain 的結構。但 advisor 指出這會建立和 <code>research/career-wiki/</code> 的平行結構，違反 workspace 的「更簡單被維護」目標。正確做法：先問「現有哪些構件已經滿足這個需求？」，只補真正缺失的。</p><p>這個教訓對應到 Lesson 2026-05-25 (a) 和 (e) 的精神：gap analysis 優先，避免重做已滿足項。</p><h3 id="反模式-2-metadata-預設非空值" tabindex="-1">反模式 2：METADATA 預設非空值 <a class="header-anchor" href="#反模式-2-metadata-預設非空值" aria-label="Permalink to &quot;反模式 2：METADATA 預設非空值&quot;">​</a></h3><p>如果自動填 <code>quality_score: 7.5</code>（一個看起來合理的初始值），後續的 skill-evolution 分析會把它當真實數據處理，無法區分「已評估為 7.5」和「從未評估」。空值 (<code>null</code>) 是更誠實的初始狀態。</p><h3 id="反模式-3-brain-first-沒有「回流義務」" tabindex="-1">反模式 3：brain-first 沒有「回流義務」 <a class="header-anchor" href="#反模式-3-brain-first-沒有「回流義務」" aria-label="Permalink to &quot;反模式 3：brain-first 沒有「回流義務」&quot;">​</a></h3><p>如果只定義「先查 brain」但不定義「查完後要回填知識」，brain-first 只能消耗知識，不能累積知識。最終 brain 的覆蓋率不增長，WebSearch 的觸發比例永遠不下降。</p><p>Post-Discovery 的四選一（Ingest/Archive/Memorize/Skip）把「靜默跳過」變成需要明示的選擇，強制 agent 每次都為知識累積做出貢獻。</p><hr><h2 id="_7-前沿趨勢與預測" tabindex="-1">7. 前沿趨勢與預測 <a class="header-anchor" href="#_7-前沿趨勢與預測" aria-label="Permalink to &quot;7. 前沿趨勢與預測&quot;">​</a></h2><h3 id="_7-1-typed-knowledge-graph-的必要性日增" tabindex="-1">7.1 Typed Knowledge Graph 的必要性日增 <a class="header-anchor" href="#_7-1-typed-knowledge-graph-的必要性日增" aria-label="Permalink to &quot;7.1 Typed Knowledge Graph 的必要性日增&quot;">​</a></h3><p>隨著 workspace 規模擴大（skills 從 13 增至 19，refs 從少量增至 28+），純文本搜尋的精度下降。GBrain 的 typed edges 代表了知識組織的下一步：從「哪裡有相關文字」到「構件間有什麼語意關係」。預計 cc-workspace 在未來 3–6 個月會自然發展出更多 <code>contradicts</code> 和 <code>supersedes</code> 類型的邊，因為這是知識系統成熟時自然產生的清理需求。</p><h3 id="_7-2-skill-telemetry-驅動的資源分配" tabindex="-1">7.2 Skill Telemetry 驅動的資源分配 <a class="header-anchor" href="#_7-2-skill-telemetry-驅動的資源分配" aria-label="Permalink to &quot;7.2 Skill Telemetry 驅動的資源分配&quot;">​</a></h3><p>一旦 <code>usage_count</code> 開始被記錄，workspace 維護就能從主觀判斷（「這個 skill 感覺很常用」）轉為數據驅動（「這個 skill 被呼叫 23 次，gotchas_count 升至 8，refinement_count 仍為 0 → 最需要改良」）。Hermes 的自我演化精神最終落地於此。</p><h3 id="_7-3-brain-first-作為-cost-engineering-的一部分" tabindex="-1">7.3 Brain-First 作為 Cost Engineering 的一部分 <a class="header-anchor" href="#_7-3-brain-first-作為-cost-engineering-的一部分" aria-label="Permalink to &quot;7.3 Brain-First 作為 Cost Engineering 的一部分&quot;">​</a></h3><p>隨著 token 成本管理變得更重要（MEMORY.md 的 token budget 優化記錄表明這是持續關注點），brain-first lookup 的每次命中都是一次省 token 的機會。若 career-wiki 能覆蓋 40% 的架構查詢，等效於每 session 省 5–10 次 WebSearch 往返。</p><hr><h2 id="_8-可立即實作的行動建議" tabindex="-1">8. 可立即實作的行動建議 <a class="header-anchor" href="#_8-可立即實作的行動建議" aria-label="Permalink to &quot;8. 可立即實作的行動建議&quot;">​</a></h2><ol><li><strong>LOG.md 第一條用戶更新</strong>：下次執行 <code>wiki-lint.sh</code> 後，手動在 LOG.md 加入 <code>[LINT]</code> 條目（建立使用習慣）</li><li><strong>腦優先查找試跑</strong>：下個需要知識的任務，先 <code>grep -i &lt;keyword&gt; research/RESEARCH-INDEX.md</code> 再決定是否 WebSearch（驗證四層 hierarchy 的實用性）</li><li><strong>METADATA 第一次填值</strong>：下次執行任一 skill 後，手動更新 <code>last_invoked</code> 和 <code>usage_count</code>（一旦有真實數據，skill-evolution 的分析才有意義）</li><li><strong>Typed edges 擴展</strong>：每次發現新的「此構件基於某研究」關係，在 RESEARCH-INDEX typed edges 表新增一行（保持 graph 更新）</li><li><strong>brain-first-protocol.md 加入 HANDOFF</strong>：在 <code>.claude/HANDOFF.md</code> 的「相關檔案」欄位加入 <code>brain-first-protocol.md</code> 的引用（確保 rewind 後新 session 知道此協議存在）</li></ol><hr><h2 id="附錄-來源評分與索引" tabindex="-1">附錄：來源評分與索引 <a class="header-anchor" href="#附錄-來源評分與索引" aria-label="Permalink to &quot;附錄：來源評分與索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>來源</th><th>影響力</th><th>原創性</th><th>可操作性</th><th>可信度</th><th>時效性</th><th>加權分</th></tr></thead><tbody><tr><td>Karpathy LLM Wiki gist</td><td>A</td><td>A</td><td>A</td><td>A</td><td>A</td><td>9.5/10</td></tr><tr><td>GBrain (garrytan/gbrain)</td><td>A</td><td>A</td><td>B</td><td>A</td><td>A</td><td>9.2/10</td></tr><tr><td>Hermes Agent (nousresearch)</td><td>B</td><td>A</td><td>A</td><td>A</td><td>A</td><td>9.0/10</td></tr></tbody></table><p><strong>Karpathy 核心引用</strong>：「The tedious part of maintaining a knowledge base is not the reading or the thinking — it&#39;s the bookkeeping.」</p><p><strong>GBrain 核心引用</strong>：「Search gives you raw pages. GBrain gives you the answer.」/ 「+31.4 points precision improvement at rank 5 vs vector-only」</p><p><strong>Hermes 核心引用</strong>：「The agent that grows with you」/ 「built-in learning loop — it creates skills from experience, improves them during use」</p><hr><p><em>生成工具：overnight-research pipeline / Branch：claude/workspace-architecture-update-M6mXu</em></p>',115)])])}const m=t(d,[["render",i]]);export{g as __pageData,m as default};
